#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>

#define N 100005
#define M 20

int T, n, q, p[N], u, v, d[N], f[N][M], g[N][M];

int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d%d", &n, &q);
        for (int i = 1; i <= n; i++) {
            scanf("%d", &p[i]);
        }
        for (int i = 1; i <= n; i++) {
            d[i] = 0;
            f[i][0] = g[i][0] = i;
        }
        for (int j = 1; j <= 18; j++) {
            for (int i = 1; i <= n; i++) {
                if (f[i][j - 1] != 0) {
                    f[i][j] = f[f[i][j - 1]][j - 1];
                }
                if (g[i][j - 1] != 0) {
                    g[i][j] = g[g[i][j - 1]][j - 1];
                }
            }
        }
        for (int i = 1; i <= q; i++) {
            scanf("%d%d", &u, &v);
            int l = 0, r = 18, ans = 0;
            while (l <= r) {
                int mid = (l + r) / 2;
                if (f[u][mid] != 0 && f[v][mid] != 0 && f[u][mid] < f[v][mid]) {
                    ans = mid;
                    l = mid + 1;
                } else {
                    r = mid - 1;
                }
            }
            if (f[u][ans] == 0 || f[v][ans] == 0) {
                printf("-1\n");
            } else {
                int x = f[u][ans], y = f[v][ans];
                while (x != y) {
                    if (d[x] > d[y]) {
                        x = f[x][ans];
                    } else {
                        y = f[y][ans];
                    }
                }
                printf("%d\n", d[x] + d[y] - 2 * d[f[x][ans]]);
            }
        }
    }
    return 0;
}

